const express = require('express');
const crypto = require('crypto');
const url = require('url');

const app = express();
app.use(express.urlencoded({ extended: true }));

// In-memory storage for authorization codes
const authCodes = {};

// Authorization endpoint
app.get('/authorize', (req, res) => {
  const { client_id, redirect_uri, scope } = req.query;
  if (!client_id || !redirect_uri || !scope) {
    return res.status(400).send('Missing required parameters');
  }

  // Store the state in session or cookie for security
  const state = crypto.randomBytes(16).toString('hex');

  // Save state and redirect URI in memory
  authCodes[state] = { client_id, redirect_uri };

  // Redirect to authorization page with state parameter
  res.redirect(`https://example.com/auth?client_id=${client_id}&redirect_uri=${encodeURIComponent(redirect_uri)}&scope=${scope}&state=${state}`);
});

// Token endpoint
app.post('/token', (req, res) => {
  const { code, redirect_uri } = req.body;
  if (!code || !redirect_uri) {
    return res.status(400).send('Missing required parameters');
  }

  // Check if the authorization code exists and is valid
  for (const state in authCodes) {
    if (authCodes[state].code === code && authCodes[state].redirect_uri === redirect_uri) {
      // Remove the authorization code from memory
      delete authCodes[state];

      // Generate an access token
      const accessToken = crypto.randomBytes(32).toString('hex');

      // Redirect to the provided redirect URI with the access token and state
      res.redirect(`${authCodes[state].redirect_uri}?code=${accessToken}&state=${state}`);
      return;
    }
  }

  res.status(400).send('Invalid authorization code');
});

